// Imagens embutidas como data URI (base64). Motivo: no build standalone o <Image>
// com require(png) NAO renderiza (a pipeline de asset falha), mas o ICONE nativo
// funciona -> nao e o PNG, e a resolucao do require. Base64 vira parte do bundle JS,
// entao carrega junto com o codigo e NAO depende da pipeline de asset.
export const CACHORRO_URI = 'data:image/png;base64,';
export const SPLASH_URI = 'data:image/png;base64,';
